def solve(nums: Array[Long], maxC: Long): Long = {
  val n = nums.length
  if (n == 0) return 0L
  var low = 0L
  var high = n.toLong
  var answer = n
  while (low <= high) {
    val mid = (low + high) / 2
    if (isPossible(mid, nums, maxC)) {
      answer = mid
      high = mid - 1
    } else {
      low = mid + 1
    }
  }
  answer
}

def isPossible(K: Long, nums: Array[Long], maxC: Long): Boolean = {
  val n = nums.length
  if (K == 0L) {
    return maxC >= n.toLong
  }
  val windowLength = K + 1
  if (windowLength > n) {
    return true
  }
  val intervals = (0 until (n - windowLength + 1)).map(i => (i, i + windowLength - 1)).toSeq
  val sorted = intervals.sortBy(_._2)
  var count = 0L
  var last = -1
  for (interval <- sorted) {
    val (start, end) = interval
    if (start > last) {
      count += 1
      last = end
      if (count > maxC) return false
    }
  }
  count <= maxC
}
